<?php include __DIR__.'/_init.php';$s=current_student();$q=$db->prepare('SELECT * FROM payments WHERE student_id=? ORDER BY created_at DESC');$q->execute([$s['id']]);$rows=$q->fetchAll(); ?><h3>Payment History</h3><table class="table"><tr><th>Date</th><th>Amount</th><th>Status</th><th>Invoice</th></tr><?php foreach($rows as $r):?><tr><td><?=e($r['created_at'])?></td><td>₹<?=e($r['amount'])?></td><td><span class="badge bg-<?= $r['status']==='paid'?'success':'secondary'?>"><?=e($r['status'])?></span></td><td><a href="/student/invoice.php?id=<?=$r['id']?>">View</a></td></tr><?php endforeach;?></table>
